const items = $input.all();
const activeData = items[0]?.json || {};
const predData = items[1]?.json || {};

const reports = activeData.reports || [];
const predictions = predData.predictions || [];
const count = reports.length;

const criticalReports = reports.filter(r => r.severity === 'Critical' || (r.custom_fields && r.custom_fields.criticalServicesImpacted));
const longOutages = reports.filter(r => r.custom_fields && (r.custom_fields.outageDurationHours || 0) >= 4);
const areaWide = reports.filter(r => r.custom_fields && r.custom_fields.areaWide === true);

// Priority escalation rules
let severity = 'Low';
let probability = 0.1;
let shouldAlert = false;

if (criticalReports.length >= 1) {
  severity = 'Critical'; probability = 0.92; shouldAlert = true;
} else if (areaWide.length >= 1 || count >= 15) {
  severity = 'High'; probability = 0.75; shouldAlert = true;
} else if (longOutages.length >= 3 || count >= 8) {
  severity = 'High'; probability = 0.65; shouldAlert = true;
} else if (count >= 3) {
  severity = 'Medium'; probability = 0.40; shouldAlert = true;
}

// Also escalate from AI predictions
const criticalPred = predictions.find(p => p.severity === 'Critical');
if (criticalPred && !shouldAlert) {
  severity = 'High'; probability = criticalPred.probability || 0.7; shouldAlert = true;
}

return [{ json: {
  incidentType: 'power_outage',
  severity,
  probability,
  reportCount: count,
  criticalReports: criticalReports.length,
  areaWideReports: areaWide.length,
  longOutages: longOutages.length,
  shouldAlert,
  timestamp: new Date().toISOString()
}}];
